#include <iostream>
#include <string>
#include <vector>
#include <sstream>
#include <streambuf>

// Declare the solution_logic function from the user's code
extern int solution_logic();

// Function to run the main logic with redirected I/O
std::string run_test(const std::string& input_str) {
    std::stringstream ss_input(input_str);
    std::stringstream ss_output;

    // Save original cin/cout buffers
    std::streambuf* old_cin_buf = std::cin.rdbuf();
    std::streambuf* old_cout_buf = std::cout.rdbuf();

    // Redirect cin and cout
    std::cin.rdbuf(ss_input.rdbuf());
    std::cout.rdbuf(ss_output.rdbuf());

    // Call the solution's logic function
    solution_logic(); // We ignore the return code here for simplicity in output capture

    // Restore original cin/cout buffers
    std::cin.rdbuf(old_cin_buf);
    std::cout.rdbuf(old_cout_buf);

    return ss_output.str();
}

int main() {
    // This main is for the driver itself, it won't be executed for testing individual solutions.
    // The `run_test` function is expected to be called by an external test harness.
    std::cout << "Driver loaded. Ready to run tests.\n";
    return 0;
}
